// ─────────────────── Options ────────────────────────────────────────────────────────


// ─────────────────── State ──────────────────────────────────────────────────────────
const allRows = ref<RowItem[]>([...MOCK_DATA]);

const state = reactive({
  loading:     false,
  selectedRow: null as RowItem | null,
  pageSize:    20,
  page:        { first: 0, rows: 20 },
});

const searchParams = reactive({
  educationYear: undefined as number | undefined,
  userId: '',
  userName: '',
  departmentName: '',
  completionDateRangeFrom: '',
  completionDateRangeTo: '',
});

// ─────────────────── Computed ───────────────────────────────────────────────────────
const filteredRows = computed<RowItem[]>(() => {
  let rows = allRows.value;
  if (searchParams.educationYear != null) rows = rows.filter(r => r.educationYear === searchParams.educationYear);
  if (searchParams.userId) rows = rows.filter(r => r.userId.includes(searchParams.userId));
  if (searchParams.userName) rows = rows.filter(r => r.userName.includes(searchParams.userName));
  if (searchParams.departmentName) rows = rows.filter(r => r.departmentName.includes(searchParams.departmentName));
  if (searchParams.completionDateRangeFrom) rows = rows.filter(r => r.completionDateRange >= searchParams.completionDateRangeFrom);
  if (searchParams.completionDateRangeTo)   rows = rows.filter(r => r.completionDateRange <= searchParams.completionDateRangeTo);
  return rows;
});

const pagedRows = computed<RowItem[]>(() =>
  filteredRows.value.slice(state.page.first, state.page.first + state.pageSize)
);

// ─────────────────── Handlers ───────────────────────────────────────────────────────
function onSearch(): void {
  state.page        = { first: 0, rows: state.pageSize };
  state.selectedRow = null;
}

function onReset(): void {
  Object.assign(searchParams, { educationYear: undefined, userId: '', userName: '', departmentName: '', completionDateRangeFrom: '', completionDateRangeTo: '' });
  onSearch();
}

function onRowSelect(event: { data: RowItem }): void {
  state.selectedRow = event.data;
}

function onPageChange(event: { first: number; rows: number }): void {
  state.page = event;
}

function onEdit(): void {
  // TODO: 수정 화면으로 이동 또는 모달 오픈
  console.log('[scaffold] onEdit →', state.selectedRow);
}

function onDelete(): void {
  if (!state.selectedRow) return;
  allRows.value     = allRows.value.filter(r => r.id !== state.selectedRow!.id);
  state.selectedRow = null;
}
